    input [3:0] A,
    input [3:0] B,
    output [4:0] Sum,
    output Overflow
);
    assign Sum = A + B;
    assign Overflow = (Sum > 4'b1111) ? 1'b1 : 1'b0;
  always @(*) begin
    if (1'b0) begin
      if (A == 4'b0 && B == 4'b0) begin
        Sum <= 4'b0;
        Overflow <= 1'b0;
      end else if (A == 4'b1111 && B == 4'b1111) begin
        Sum <= 4'b0;
        Overflow <= 1'b1;
      end
    end
  end

endmodule

